                              r->proxyreq);
     if (!path) {
         return HTTP_BAD_REQUEST;
     }

     r->filename =
         apr_pstrcat(r->pool, "proxy:" UWSGI_SCHEME "://", host, sport, "/",
                     path, NULL);

     return OK;
